	@Inject
	public DcDslGrammarAccess(GrammarProvider grammarProvider,
			TerminalsGrammarAccess gaTerminals) {
		this.grammar = internalFindGrammar(grammarProvider);
		this.gaTerminals = gaTerminals;
		this.pDockerCompose = new DockerComposeElements();
		this.pEString = new EStringElements();
		this.pBlockString = new BlockStringElements();
		this.pReservedWord = new ReservedWordElements();
		this.pKeyName = new KeyNameElements();
		this.pKeyValuePair = new KeyValuePairElements();
		this.pEnvEntry = new EnvEntryElements();
		this.pService = new ServiceElements();
		this.pServiceVolume = new ServiceVolumeElements();
		this.pNamedVolume = new NamedVolumeElements();
		this.pBuild = new BuildElements();
		this.pBuildValue = new BuildValueElements();
		this.pBuildObject = new BuildObjectElements();
		this.pNetworks = new NetworksElements();
		this.pNetwork = new NetworkElements();
		this.pConfig = new ConfigElements();
		this.pDepends_on = new Depends_onElements();
		this.pDb = new DbElements();
		this.pHealthcheck = new HealthcheckElements();
		this.pSecret = new SecretElements();
		this.pResource = new ResourceElements();
		this.pEBoolean = new EBooleanElements();
		this.tBEG_BLOCK = (TerminalRule) GrammarUtil.findRuleForName(getGrammar(), "pt.isep.yamldslgen.dockercompose.xtext.DcDsl.BEG_BLOCK");
		this.tEND_BLOCK = (TerminalRule) GrammarUtil.findRuleForName(getGrammar(), "pt.isep.yamldslgen.dockercompose.xtext.DcDsl.END_BLOCK");
		this.tSQ_STRING = (TerminalRule) GrammarUtil.findRuleForName(getGrammar(), "pt.isep.yamldslgen.dockercompose.xtext.DcDsl.SQ_STRING");
		this.tSL_COMMENT = (TerminalRule) GrammarUtil.findRuleForName(getGrammar(), "pt.isep.yamldslgen.dockercompose.xtext.DcDsl.SL_COMMENT");
		this.tGH_EXPRESSION = (TerminalRule) GrammarUtil.findRuleForName(getGrammar(), "pt.isep.yamldslgen.dockercompose.xtext.DcDsl.GH_EXPRESSION");
		this.tINT = (TerminalRule) GrammarUtil.findRuleForName(getGrammar(), "pt.isep.yamldslgen.dockercompose.xtext.DcDsl.INT");
		this.tYAML_SCALAR = (TerminalRule) GrammarUtil.findRuleForName(getGrammar(), "pt.isep.yamldslgen.dockercompose.xtext.DcDsl.YAML_SCALAR");
	}
	
	protected Grammar internalFindGrammar(GrammarProvider grammarProvider) {
		Grammar grammar = grammarProvider.getGrammar(this);
		while (grammar != null) {
			if ("pt.isep.yamldslgen.dockercompose.xtext.DcDsl".equals(grammar.getName())) {
				return grammar;
			}
			List<Grammar> grammars = grammar.getUsedGrammars();
			if (!grammars.isEmpty()) {
				grammar = grammars.iterator().next();
			} else {
				return null;
			}
		}
		return grammar;
	}
	
	@Override
	public Grammar getGrammar() {
		return grammar;
	}
	
	
	public TerminalsGrammarAccess getTerminalsGrammarAccess() {
		return gaTerminals;
	}

	
